1	package session
2	
3	import "irrlicht/core/domain/orchestrator"
4	
5	// DashboardResponse is the unified API response containing the full
6	// Orchestrator → Group → Agent → Children hierarchy.
7	type DashboardResponse struct {
8		Orchestrator *OrchestratorSummary `json:"orchestrator,omitempty"`
9		Groups       []*AgentGroup        `json:"groups"`
10	}
11	
12	// OrchestratorSummary holds structural orchestrator info (adapter, status,
13	// work units). Individual worker states are represented as Agents, not here.
14	type OrchestratorSummary struct {
15		Adapter   string             `json:"adapter"`
16		Running   bool               `json:"running"`
17		WorkUnits []WorkUnitSummary  `json:"work_units,omitempty"`
18	}
19	
20	// WorkUnitSummary represents a trackable unit of work (convoy, task list).
21	type WorkUnitSummary struct {
22		ID     string `json:"id"`
23		Type   string `json:"type"`
24		Name   string `json:"name"`
25		Source string `json:"source"`
26		Total  int    `json:"total"`
27		Done   int    `json:"done"`
28	}
29	
30	// AgentGroup is a collection of agents working on the same project or rig.
31	type AgentGroup struct {
32		Name   string   `json:"name"`
33		Status string   `json:"status,omitempty"`
34		Agents []*Agent `json:"agents"`
35	}
36	
37	// Agent is a session with optional orchestrator role and nested children.
38	type Agent struct {
39		*SessionState
40		Role        string   `json:"role,omitempty"`
41		Icon        string   `json:"icon,omitempty"`
42		Description string   `json:"description,omitempty"`
43		WorkerName  string   `json:"worker_name,omitempty"`
44		WorkerID    string   `json:"worker_id,omitempty"`
45		Children    []*Agent `json:"children,omitempty"`
46	}
47	
48	// workerInfo holds orchestrator metadata for a matched session.
49	type workerInfo struct {
50		Role        string
51		Icon        string
52		Description string
53		Rig         string
54		Name        string
55		ID          string
56	}
57	
58	// BuildDashboard creates a hierarchical DashboardResponse from a flat list
59	// of sessions and optional orchestrator state. Sessions are grouped by rig
60	// (if matched to an orchestrator worker) or by ProjectName.
61	func BuildDashboard(sessions []*SessionState, orch *orchestrator.State) *DashboardResponse {
62		resp := &DashboardResponse{}
63	
64		// 1. Build orchestrator summary + session-to-worker map.
65		workerMap := map[string]*workerInfo{}
66		if orch != nil && orch.Running {
67			resp.Orchestrator = buildOrchestratorSummary(orch)
68			workerMap = buildWorkerMap(orch)
69		}
70	
71		// 2. Index sessions and identify parent-child relationships.
72		byID := make(map[string]*SessionState, len(sessions))
73		for _, s := range sessions {
74			byID[s.SessionID] = s
75		}
76	
77		childIDs := make(map[string]bool)
78		parentChildren := make(map[string][]*SessionState)
79		for _, s := range sessions {
80			if s.ParentSessionID != "" {
81				if _, ok := byID[s.ParentSessionID]; ok {
82					childIDs[s.SessionID] = true
83					parentChildren[s.ParentSessionID] = append(parentChildren[s.ParentSessionID], s)
84				}
85			}
86		}
87	
88		// 3. Build agent trees from top-level sessions and collect into groups.
89		groupMap := make(map[string]*AgentGroup)
90		var groupOrder []string
91	
92		for _, s := range sessions {
93			if childIDs[s.SessionID] {
94				continue
95			}
96	
97			agent := buildAgent(s, workerMap, parentChildren)
98	
99			// Determine group key: rig name from orchestrator, or project name.
100			groupKey := s.ProjectName
101			if wi, ok := workerMap[s.SessionID]; ok && wi.Rig != "" {
102				groupKey = wi.Rig
103			}
104			if groupKey == "" {
105				groupKey = "unknown"
106			}
107	
108			g, ok := groupMap[groupKey]
109			if !ok {
110				g = &AgentGroup{Name: groupKey}
111				groupMap[groupKey] = g
112				groupOrder = append(groupOrder, groupKey)
113			}
114			g.Agents = append(g.Agents, agent)
115		}
116	
117		// 4. Annotate groups with orchestrator codebase status.
118		if orch != nil {
119			for _, cb := range orch.Codebases {
120				if g, ok := groupMap[cb.Name]; ok {
121					g.Status = cb.Status
122				}
123			}
124		}
125	
126		// 5. Assemble ordered groups.
127		resp.Groups = make([]*AgentGroup, 0, len(groupOrder))
128		for _, key := range groupOrder {
129			resp.Groups = append(resp.Groups, groupMap[key])
130		}
131	
132		return resp
133	}
