135	// buildAgent recursively creates an Agent tree from a session and its children.
136	func buildAgent(s *SessionState, workerMap map[string]*workerInfo, parentChildren map[string][]*SessionState) *Agent {
137		agent := &Agent{SessionState: s}
138	
139		// Annotate with orchestrator role.
140		if wi, ok := workerMap[s.SessionID]; ok {
141			agent.Role = wi.Role
142			agent.Icon = wi.Icon
143			agent.Description = wi.Description
144			agent.WorkerName = wi.Name
145			agent.WorkerID = wi.ID
146		}
147	
148		// Attach children recursively.
149		if children, ok := parentChildren[s.SessionID]; ok {
150			agent.Children = make([]*Agent, 0, len(children))
151			for _, c := range children {
152				agent.Children = append(agent.Children, buildAgent(c, workerMap, parentChildren))
153			}
154		}
155	
156		// Unify subagents summary: merge in-process agents with file-based children.
157		unifySubagents(agent)
158	
159		return agent
160	}
161	
162	// unifySubagents recomputes the Subagents summary for an agent by merging
163	// the adapter-reported in-process count (metrics.OpenSubagents) with the
164	// file-based children attached to the agent tree. Delegates to
165	// ComputeSubagentSummary so the detector and REST path share one formula.
166	func unifySubagents(a *Agent) {
167		children := make([]*SessionState, 0, len(a.Children))
168		for _, c := range a.Children {
169			children = append(children, c.SessionState)
170		}
171		a.Subagents = ComputeSubagentSummary(a.SessionState, children)
172	}
173	
174	// ComputeSubagentSummary returns the unified subagent summary for a parent
175	// session. The "in-process" component comes from the adapter via
176	// parent.Metrics.OpenSubagents (e.g. claudecode counts open Agent tool calls);
177	// the "file-based" component comes from child sessions in childSessions whose
178	// ParentSessionID matches the parent. Passing nil or an empty slice for
179	// childSessions skips the file-based contribution. Returns nil when there are
180	// no subagents at all, so callers can leave Subagents unset on the wire.
181	func ComputeSubagentSummary(parent *SessionState, childSessions []*SessionState) *SubagentSummary {
182		inProcess := 0
183		if parent != nil && parent.Metrics != nil {
184			inProcess = parent.Metrics.OpenSubagents
185		}
186	
187		var fileChildren []*SessionState
188		if parent != nil {
189			for _, c := range childSessions {
190				if c != nil && c.ParentSessionID == parent.SessionID {
191					fileChildren = append(fileChildren, c)
192				}
193			}
194		}
195	
196		if inProcess == 0 && len(fileChildren) == 0 {
197			return nil
198		}
199	
200		summary := &SubagentSummary{
201			Total:   inProcess + len(fileChildren),
202			Working: inProcess, // in-process agents are always working
203		}
204		for _, c := range fileChildren {
205			switch c.State {
206			case StateWorking:
207				summary.Working++
208			case StateWaiting:
209				summary.Waiting++
210			case StateReady:
211				summary.Ready++
212			}
213		}
214		return summary
215	}
216	
217	// buildOrchestratorSummary creates a lightweight summary from orchestrator state.
218	func buildOrchestratorSummary(orch *orchestrator.State) *OrchestratorSummary {
219		summary := &OrchestratorSummary{
220			Adapter: orch.Adapter,
221			Running: orch.Running,
222		}
223		for _, wu := range orch.WorkUnits {
224			summary.WorkUnits = append(summary.WorkUnits, WorkUnitSummary{
225				ID:     wu.ID,
226				Type:   wu.Type,
227				Name:   wu.Name,
228				Source: wu.Source,
229				Total:  wu.Total,
230				Done:   wu.Done,
231			})
232		}
233		return summary
234	}
235	
236	// buildWorkerMap creates a sessionID → workerInfo index from orchestrator state.
237	func buildWorkerMap(orch *orchestrator.State) map[string]*workerInfo {
238		m := make(map[string]*workerInfo)
239	
240		for _, ga := range orch.GlobalAgents {
241			if ga.SessionID != "" {
242				m[ga.SessionID] = &workerInfo{
243					Role:        ga.Role,
244					Icon:        ga.Icon,
245					Description: ga.Description,
246				}
247			}
248		}
249	
250		for _, cb := range orch.Codebases {
251			for _, wt := range cb.Worktrees {
252				for _, w := range wt.Workers {
253					if w.SessionID != "" {
254						m[w.SessionID] = &workerInfo{
255							Role:        w.Role,
256							Icon:        w.Icon,
257							Description: w.Description,
258							Rig:         cb.Name,
259							Name:        w.Name,
260							ID:          w.ID,
261						}
262					}
263				}
264			}
265		}
266	
267		return m
268	}
