8	func TestIsStale(t *testing.T) {
9		now := time.Now().Unix()
10	
11		tests := []struct {
12			name      string
13			updatedAt int64
14			maxAge    time.Duration
15			want      bool
16		}{
17			{"fresh session", now - 60, 5 * 24 * time.Hour, false},
18			{"stale session", now - 6*24*60*60, 5 * 24 * time.Hour, true},
19			{"exactly at boundary", now - 5*24*60*60 - 1, 5 * 24 * time.Hour, true},
20			{"zero maxAge disables", now - 999*24*60*60, 0, false},
21			{"negative maxAge disables", now - 999*24*60*60, -1, false},
22		}
23	
24		for _, tt := range tests {
25			t.Run(tt.name, func(t *testing.T) {
26				s := &SessionState{UpdatedAt: tt.updatedAt}
27				if got := s.IsStale(tt.maxAge); got != tt.want {
28					t.Errorf("IsStale(%v) = %v, want %v", tt.maxAge, got, tt.want)
29				}
30			})
31		}
32	}
