256			got := ComputeSubagentSummary(parent, children)
257			if got == nil {
258				t.Fatal("got nil, want summary")
259			}
260			// 2 in-process (always working) + 1 working file + 1 waiting file.
261			if got.Total != 4 || got.Working != 3 || got.Waiting != 1 {
262				t.Errorf("got %+v, want total=4 working=3 waiting=1", got)
263			}
264		})
